async fn handle_connection(
    stream: TcpStream,
    config: Arc<AppConfig>,
    state: Arc<StateStore>,
    runtime: Arc<RuntimeState>,
    load_balancer: Arc<LoadBalancer>,
) {
    let target = parse_connect_request(&stream).await?;

    // Try normal proxy selection first
    let proxy_result = load_balancer.select_proxy(
        config.settings.load_balance_strategy,
        &config.proxies,
        &state,
    ).await;

    let (proxy_stream, proxy_id) = match proxy_result {
        Some(proxy_id) => {
            // Normal path - healthy proxy available
            let proxy = config.proxies.iter().find(|p| p.id == proxy_id).unwrap();
            let stream = connect_through_proxy(proxy, &target).await?;
            (stream, proxy_id)
