 {"id":"rust_proxy-uue","title":"Implement proxy selection logic for all strategies","description":"## Scope

Implement the core proxy selection logic that supports all load balancing strategies.

## Location

Add to `state.rs` in the `RuntimeState` impl block, or create new `load_balancer.rs` module.

## Implementation

```rust
use std::sync::atomic::{AtomicUsize, Ordering};

pub struct LoadBalancer {
    round_robin_counter: AtomicUsize,
}

impl LoadBalancer {
    pub fn new() -> Self {
        Self {
            round_robin_counter: AtomicUsize::new(0),
        }
    }

    /// Select a proxy based on the configured strategy
    pub async fn select_proxy(
        &self,
        strategy: LoadBalanceStrategy,
        proxies: &[ProxyConfig],
        state: &StateStore,
    ) -> Option<String> {
        // Get healthy proxies
        let healthy: Vec<_> = proxies
            .iter()
            .filter(|p| {
                // Check health status from state
                futures::executor::block_on(state.get_health_status(&p.id))
                    == HealthStatus::Healthy
            })
            .collect();

        if healthy.is_empty() {
            return None; // Will trigger degradation policy
        }

        match strategy {
            LoadBalanceStrategy::Single => {
                // Return highest priority (lowest number) healthy proxy
                healthy.iter()
                    .min_by_key(|p| p.priority.unwrap_or(100))
                    .map(|p| p.id.clone())
            }
            LoadBalanceStrategy::RoundRobin => {
                let idx = self.round_robin_counter.fetch_add(1, Ordering::Relaxed);
                healthy.get(idx % healthy.len()).map(|p| p.id.clone())
            }
            LoadBalanceStrategy::LeastLatency => {
                // Get latency from state, pick lowest
                let mut with_latency: Vec<_> = healthy.iter()
                    .map(|p| {
                        let latency = futures::executor::block_on(
                            state.get_latency(&p.id)
                        ).unwrap_or(f64::MAX);
                        (p, latency)
                    })
                    .collect();
                with_latency.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
                with_latency.first().map(|(p, _)| p.id.clone())
            }
            LoadBalanceStrategy::Weighted => {
                // Weighted random selection
                let total_weight: u32 = healthy.iter().map(|p| p.weight).sum();
                if total_weight == 0 {
                    return healthy.first().map(|p| p.id.clone());
                }
                let mut rng = rand::thread_rng();
                let target = rng.gen_range(0..total_weight);
                let mut cumulative = 0;
                for proxy in &healthy {
                    cumulative += proxy.weight;
                    if target < cumulative {
                        return Some(proxy.id.clone());
                    }
                }
                healthy.last().map(|p| p.id.clone())
            }
        }
    }
}
```

